-- 换服功能
teleportTab:Button({
    Title = "loc:CHANGE_SERVER",
    Desc = "切换到其他服务器",
    Callback = function()
        local http = game:GetService("HttpService")
        local teleport = game:GetService("TeleportService")
        local players = game:GetService("Players")

        local function getServers()
            local cursor = ""
            local servers = {}
            
            repeat
                local url = string.format("https://games.roblox.com/v1/games/%s/servers/Public?sortOrder=2&limit=100%s", game.PlaceId, cursor ~= "" and "&cursor=" .. cursor or "")
                
                local success, result = pcall(function()
                    return http:JSONDecode(game:HttpGet(url))
                end)
                
                if success and result.data then
                    for _, server in ipairs(result.data) do
                        if server.id ~= game.JobId and server.playing < server.maxPlayers then
                            table.insert(servers, server.id)
                        end
                    end
                    cursor = result.nextPageCursor
                else
                    warn("获取服务器失败")
                    break
                end
            until not cursor
            
            return servers
        end

        local servers = getServers()
        if #servers > 0 then
            local randomServer = servers[math.random(1, #servers)]
            teleport:TeleportToPlaceInstance(game.PlaceId, randomServer, players.LocalPlayer)
        else
            warn("没有找到可以跳转的服务器")
        end
    end
})

