-- 自动刷Boss
bossLeftTab:Button({
    Title = "loc:AUTO_FARM_BOSS",
    Desc = "电脑和手机通用",
    Callback = function()
        task.spawn(function()
            while wait() do
                if not game:IsLoaded() then
                    game.Loaded:Wait()
                end
                
                -- 禁用反挂机
                for _, connection in pairs(getconnections(game.Players.LocalPlayer.Idled)) do
                    connection:Disable()
                end
                
                local players = game:GetService("Players")
                local workspace = game:GetService("Workspace")
                
                if players.LocalPlayer.Character then
                    local character = players.LocalPlayer.Character
                    local humanoidRootPart = character:WaitForChild("HumanoidRootPart")
                    local humanoid = character:WaitForChild("Humanoid")
                    
                    -- 清理特效
                    pcall(function()
                        if workspace:FindFirstChild("Effects") then
                            workspace.Effects:Destroy()
                        end
                        if workspace:FindFirstChild("Map") then
                            if workspace.Map:FindFirstChild("ThunderParts") then
                                workspace.Map.ThunderParts:Destroy()
                            end
                        end
                    end)
                    
                    -- 装备骑士剑
                    pcall(function()
                        local sword = players.LocalPlayer.Backpack:FindFirstChild("KnightsSword") or workspace:FindFirstChild("KnightsSword")
                        if sword then
                            sword.Parent = character
                            wait(0.1)
                            pcall(function()
                                local handle = sword:FindFirstChild("Handle")
                                if handle then
                                    local selectionBox = Instance.new("SelectionBox")
                                    selectionBox.Name = "SelectionBoxCreated"
                                    selectionBox.Parent = handle
                                    selectionBox.Adornee = handle
                                    handle.Massless = true
                                    handle.Size = Vector3.new(20, 20, 500)
                                    sword.GripPos = Vector3.new(0, 0, 0)
                                end
                            end)
                            humanoid:UnequipTools()
                            sword.Parent = character
                        end
                    end)
                    
                    -- 传送到Boss位置
                    pcall(function()
                        humanoidRootPart.CFrame = CFrame.new(20.456, 113.245, 196.613)
                    end)
                    
                    -- 攻击Boss
                    pcall(function()
                        local sword = character:FindFirstChild("KnightsSword")
                        if sword then
                            sword:Activate()
                        end
                    end)
                    
                    -- 检测Boss血量
                    local bossHealth = workspace:WaitForChild("TrollHealth")
                    bossHealth:GetPropertyChangedSignal("Value"):Connect(function()
                        local maxHealth = bossHealth:FindFirstChild("MaxHealth")
                        if maxHealth and bossHealth.Value / maxHealth.Value <= 0.003 then
                            humanoid:UnequipTools()
                            wait(1)
                            -- 重新开始
                        end
                    end)
                end
            end
        end)
    end
})

