pvpLeftTab:Button({
    Title = "loc:AUTO_AIM",
    Desc = "绿宝石水花自动瞄准",
    Callback = function()
        local screenGui = Instance.new("ScreenGui", game.CoreGui)
        local button = Instance.new("TextButton")
        button.Size = UDim2.new(0.05, 0, 0.1, 0)
        button.Position = UDim2.new(0.68, 0, 0.53, 0)
        button.Text = "F"
        button.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
        button.TextColor3 = Color3.new(1, 1, 1)
        button.Parent = screenGui
        
        button.MouseButton1Click:Connect(function()
            local players = game:GetService("Players")
            local localPlayer = players.LocalPlayer
            
            -- 寻找最近的目标
            local function findClosestTarget()
                local closestPlayer = nil
                local closestDistance = math.huge
                
                for _, player in ipairs(players:GetPlayers()) do
                    if player ~= localPlayer and player.Character then
                        local hrp = player.Character:FindFirstChild("HumanoidRootPart")
                        if hrp then
                            local distance = (localPlayer.Character.HumanoidRootPart.Position - hrp.Position).Magnitude
                            if distance < closestDistance then
                                closestDistance = distance
                                closestPlayer = player
                            end
                        end
                    end
                end
                
                return closestPlayer
            end
            
            local target = findClosestTarget()
            if target and target.Character then
                local hrp = target.Character:WaitForChild("HumanoidRootPart")
                for i = 1, 30 do
                    game:GetService("ReplicatedStorage").Main.Input:FireServer("Alternate", "EmeraldProjectile2", false, hrp.CFrame)
                end
            end
        end)
    end
})

