-- "神临"
pvpLeftTab:Button({
    Title = "“神临”",
    Desc = "100%卡住，最多点一次",
    Callback = function()
        task.spawn(function()
            local players = game:GetService("Players")
            local replicatedStorage = game:GetService("ReplicatedStorage")
            local input = replicatedStorage:WaitForChild("Main"):WaitForChild("Input")
            
            local attacking = false
            
            local function attack()
                if attacking then return end
                
                local localPlayer = players.LocalPlayer
                if not localPlayer.Character then return end
                local character = localPlayer.Character
                if not character.Parent then return end
                
                local hrp = character:FindFirstChild("HumanoidRootPart")
                if not hrp then return end
                
                for _, player in ipairs(players:GetPlayers()) do
                    if player ~= localPlayer and player.Character and player.Character.Parent then
                        local targetHumanoid = player.Character:FindFirstChild("Humanoid")
                        local targetHrp = player.Character:FindFirstChild("HumanoidRootPart")
                        
                        if targetHumanoid and targetHumanoid.Health > 0 and targetHrp then
                            local distance = (hrp.Position - targetHrp.Position).Magnitude
                            if distance <= 100 then
                                local cframe = CFrame.new(hrp.Position + (targetHrp.Position - hrp.Position).Unit * 5, targetHrp.Position)
                                pcall(function()
                                    input:FireServer("Damage", "Punch", false, cframe)
                                    input:FireServer("Damage", "HeavyPunch", false, cframe)
                                    input:FireServer("Damage", "PunchBarrage", false, cframe)
                                    input:FireServer("Damage", "ScytheLMB", false, cframe)
                                end)
                            end
                        end
                    end
                end
            end
            
            if players.LocalPlayer.Character then
                local humanoid = players.LocalPlayer.Character:WaitForChild("Humanoid")
                print("脚本已启用")
                
                humanoid.Died:Connect(function()
                    attacking = false
                    print("已禁用")
                end)
                
                attacking = true
                while attacking do
                    if players.LocalPlayer.Character and players.LocalPlayer.Character.Parent then
                        attack()
                    end
                    wait(0.1)
                end
            else
                print("等待角色重生...")
                players.LocalPlayer.CharacterAdded:Wait()
                wait(1)
            end
        end)
    end
})

