                end
                
                local stand = players.LocalPlayer.Character:FindFirstChild("Stand")
                if stand then
                    local standParts = {"Stand Head", "Stand Torso", "StandHumanoidRootPart", "Stand Right Arm", "Stand Left Arm", "Stand Right Leg", "Stand Left Leg"}
                    for _, partName in ipairs(standParts) do
                        local part = stand:FindFirstChild(partName)
                        if part then
                            anchor:FireServer(part, false)
                        end
                    end
                    hideParts(stand)
                end
            end
            
            hideCharacter()
            
            players.LocalPlayer.CharacterAdded:Connect(function(character)
                task.wait(10)
                local stand = character:WaitForChild("Stand", 10)
                if stand then
                    stand.DescendantAdded:Connect(function(descendant)
                        if descendant:IsA("BasePart") then
                            anchor:FireServer(descendant, false)
                        end
                    end)
                end
                hideCharacter()
            end)
            
            wait(1)
            pcall(hideCharacter)
        end)
    end
})

