        title.TextColor3 = Color3.fromRGB(255, 255, 255)
        title.Font = Enum.Font.GothamBold
        title.TextSize = 14
        title.BackgroundTransparency = 1
        title.Parent = titleBar
        title.Active = false
        
        local minimizeButton = Instance.new("TextButton")
        minimizeButton.Size = UDim2.new(0, 30, 1, 0)
        minimizeButton.Position = UDim2.new(1, -30, 0, 0)
        minimizeButton.Text = "_"
        minimizeButton.TextColor3 = Color3.fromRGB(255, 255, 255)
        minimizeButton.BackgroundTransparency = 1
        minimizeButton.Parent = titleBar
        
        local searchBox = Instance.new("TextBox")
        searchBox.Size = UDim2.new(0.9, 0, 0, 25)
        searchBox.Position = UDim2.new(0.05, 0, 0, 35)
        searchBox.PlaceholderText = "搜索玩家..."
        searchBox.Text = ""
        searchBox.TextColor3 = Color3.fromRGB(255, 255, 255)
        searchBox.BackgroundColor3 = Color3.fromRGB(60, 60, 70)
        searchBox.Parent = mainFrame
        
        local scrollFrame = Instance.new("ScrollingFrame")
        scrollFrame.Size = UDim2.new(0.9, 0, 0, 100)
        scrollFrame.Position = UDim2.new(0.05, 0, 0, 65)
        scrollFrame.BackgroundColor3 = Color3.fromRGB(50, 50, 60)
        scrollFrame.BorderSizePixel = 0
        scrollFrame.ScrollBarThickness = 3
        scrollFrame.AutomaticCanvasSize = Enum.AutomaticSize.Y
        scrollFrame.Parent = mainFrame
        
        local trackButton = Instance.new("TextButton")
        trackButton.Size = UDim2.new(0.9, 0, 0, 30)
        trackButton.Position = UDim2.new(0.05, 0, 0, 170)
        trackButton.Text = "开始追踪"
        trackButton.TextColor3 = Color3.fromRGB(255, 255, 255)
        trackButton.Font = Enum.Font.GothamBold
        trackButton.BackgroundColor3 = Color3.fromRGB(70, 130, 180)
        trackButton.Parent = mainFrame
        
        local tracking = false
        local targetPlayer = nil
        local trackingConnection = nil
        
        local function updatePlayerList(searchText)
            scrollFrame:ClearAllChildren()
            local yOffset = 5
            
            for _, player in ipairs(players:GetPlayers()) do
                if player ~= players.LocalPlayer then
                    if searchText == "" or string.find(string.lower(player.Name), string.lower(searchText)) then
                        local button = Instance.new("TextButton")
                        button.Size = UDim2.new(1, -10, 0, 25)
                        button.Position = UDim2.new(0, 5, 0, yOffset)
                        button.Text = player.Name
                        button.TextColor3 = Color3.fromRGB(255, 255, 255)
                        button.Font = Enum.Font.Gotham
                        button.BackgroundColor3 = Color3.fromRGB(60, 60, 70)
                        button.AutoButtonColor = false
                        
                        button.MouseButton1Click:Connect(function()
                            for _, child in ipairs(scrollFrame:GetChildren()) do
                                if child:IsA("TextButton") then
                                    child.BackgroundColor3 = Color3.fromRGB(60, 60, 70)
                                end
                            end
                            button.BackgroundColor3 = Color3.fromRGB(80, 120, 200)
                            targetPlayer = player
                        end)
                        
                        button.Parent = scrollFrame
                        yOffset = yOffset + 30
                    end
                end
            end
        end
        
        updatePlayerList("")
        
        searchBox:GetPropertyChangedSignal("Text"):Connect(function()
            updatePlayerList(searchBox.Text)
        end)
        
        trackButton.MouseButton1Click:Connect(function()
            if targetPlayer then
                tracking = not tracking
                if tracking then
                    trackButton.Text = "停止追踪"
                    trackButton.BackgroundColor3 = Color3.fromRGB(180, 70, 70)
                    
                    if trackingConnection then
                        trackingConnection:Disconnect()
                    end
                    
                    trackingConnection = runService.Heartbeat:Connect(function()
                        if tracking and targetPlayer and targetPlayer.Character and players.LocalPlayer.Character then
                            local targetHrp = targetPlayer.Character:FindFirstChild("HumanoidRootPart")
                            local localHrp = players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
                            
                            if targetHrp and localHrp then
                                localHrp.CFrame = CFrame.new(targetHrp.Position + (-targetHrp.CFrame.LookVector.Unit * 5), targetHrp.Position)
                            end
                        end
                    end)
                else
                    trackButton.Text = "开始追踪"
                    trackButton.BackgroundColor3 = Color3.fromRGB(70, 130, 180)
                    
                    if trackingConnection then
                        trackingConnection:Disconnect()
                        trackingConnection = nil
                    end
                end
            end
        end)
        
        minimizeButton.MouseButton1Click:Connect(function()
            local minimized = not minimized
            if minimized then
                mainFrame.Size = UDim2.new(0, 200, 0, 30)
                searchBox.Visible = false
                scrollFrame.Visible = false
                trackButton.Visible = false
                minimizeButton.Text = "+"
            else
                mainFrame.Size = UDim2.new(0, 200, 0, 200)
                searchBox.Visible = true
                scrollFrame.Visible = true
                trackButton.Visible = true
                minimizeButton.Text = "-"
            end
        end)
    end
})

